#!/usr/bin/env python3
import base64, os
FILES = {'App.js': '', 'ThemeContext.js': '', 'storage/database.js': '', 'screens/HomeScreen.js': '', 'screens/BatListScreen.js': '', 'screens/BatProfileScreen.js': '', 'screens/CreateBatScreen.js': '', 'screens/KnockingSessionScreen.js': '', 'screens/TrendsScreen.js': '', 'screens/OtherScreens.js': '', 'screens/HeatmapScreen.js': '', 'screens/BatMapScreen.js': '', 'screens/ActivityLogScreen.js': 'ZXhwb3J0IHsgQWN0aXZpdHlMb2dTY3JlZW4gYXMgZGVmYXVsdCB9IGZyb20gJy4vT3RoZXJTY3JlZW5zJzsK', 'screens/BatCareScreen.js': 'ZXhwb3J0IHsgQmF0Q2FyZVNjcmVlbiBhcyBkZWZhdWx0IH0gZnJvbSAnLi9PdGhlclNjcmVlbnMnOwo=', 'screens/MicTestScreen.js': 'ZXhwb3J0IHsgTWljVGVzdFNjcmVlbiBhcyBkZWZhdWx0IH0gZnJvbSAnLi9PdGhlclNjcmVlbnMnOwo='}
print("BatKnock Installer v1.1.0")
print("=" * 40)
for path, data in FILES.items():
    content = base64.b64decode(data.encode()).decode("utf-8")
    d = os.path.dirname(path)
    if d and not os.path.exists(d): os.makedirs(d)
    open(path, "w", encoding="utf-8").write(content)
    print(f"Written: {path} ({os.path.getsize(path)} bytes)")
print("=" * 40)
print("Done! Run: npx expo start --clear --lan")